import{_ as a,o as i,c as t,a2 as s}from"./chunks/framework.DtwafDNl.js";const u=JSON.parse('{"title":"SIP Firewall","description":"","frontmatter":{},"headers":[],"relativePath":"features/firewall.md","filePath":"features/firewall.md"}'),l={name:"features/firewall.md"};function r(o,e,n,c,d,f){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="sip-firewall" tabindex="-1">SIP Firewall <a class="header-anchor" href="#sip-firewall" aria-label="Permalink to &quot;SIP Firewall&quot;">​</a></h1><p>SIP Firewall protects the phone system from common SIP abuse patterns such as repeated failed registrations and INVITE floods. It watches live security activity, detects suspicious behavior, and can automatically block abusive IP addresses when configured thresholds are crossed.</p><p>The firewall is designed for day-to-day operations as well as incident response. You can review a live security feed, see where traffic is coming from, manage blocked addresses, and keep trusted networks on a whitelist so legitimate devices are not interrupted.</p><p>For teams that already use fail2ban, Callytics can operate in an opt-in mode that delegates enforcement to the existing fail2ban setup instead of managing blocks directly.</p><h2 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;Capabilities&quot;">​</a></h2><ul><li>Automatic detection of registration abuse</li><li>Automatic detection of INVITE flood patterns</li><li>Threshold-based auto-blocking</li><li>Network-level blocking enforcement</li><li>Live security feed for recent firewall activity</li><li>Radar-style view of suspicious SIP activity</li><li>GeoIP country detection for remote addresses</li><li>Blocked IP management with unblock support</li><li>Whitelist support for trusted addresses and networks</li><li>Daily security statistics</li><li>Optional fail2ban enforcement mode</li></ul>',6)])])}const m=a(l,[["render",r]]);export{u as __pageData,m as default};
